import { tags } from 'decantr/tags';
import { onMount, onDestroy } from 'decantr/state';
import { css } from 'decantr/css';

code.example:
function HotkeyBar({ keys }) {
  const { div, span, kbd } = tags;

  const defaultKeys = [
    { key: 'F1', label: 'Help' },
    { key: 'F2', label: 'Menu' },
    { key: 'F3', label: 'View' },
    { key: 'F4', label: 'Edit' },
    { key: 'F5', label: 'Copy' },
    { key: 'F6', label: 'Move' },
    { key: 'F7', label: 'Mkdir' },
    { key: 'F8', label: 'Delete' },
    { key: 'F9', label: 'PullDn' },
    { key: 'F10', label: 'Quit' }
  ];

  const hotkeys = keys || defaultKeys;

  const handleKeyDown = (e) => {
    const hotkey = hotkeys.find(h => h.key === e.key);
    if (hotkey?.action) {
      e.preventDefault();
      hotkey.action();
    }
  };

  onMount(() => document.addEventListener('keydown', handleKeyDown));
  onDestroy(() => document.removeEventListener('keydown', handleKeyDown));

  return div({ class: css('_flex _aic _jcsb _h[28px] _bgsurface _borderT _bordercolor[#333]') },
    ...hotkeys.map(h =>
      div({
        class: css('_flex _aic _cursor[pointer] _hover:bgmuted/30 _px1'),
        onclick: h.action,
        title: h.description
      },
        kbd({ class: css('term-hotkey _bgprimary _fgblack _px1 _textsm _fontbold') }, h.key.replace('F', '')),
        span({ class: css('_fggreen _px1 _textsm') }, h.label)
      )
    )
  );
}

function ExtendedHotkeyBar({ keys }) {
  const defaultKeys = [
    { key: 'F1', label: 'Help' },
    { key: 'F2', label: 'Config' },
    { key: 'F3', label: 'Logs' },
    { key: 'F4', label: 'Metrics' },
    { key: 'F5', label: 'Refresh' },
    { key: 'F6', label: 'Search' },
    { key: 'F7', label: 'Filter' },
    { key: 'F8', label: 'Export' },
    { key: 'F9', label: 'Theme' },
    { key: 'F10', label: 'Settings' },
    { key: 'F11', label: 'Fullscr' },
    { key: 'F12', label: 'Quit' }
  ];
  return HotkeyBar({ keys: keys || defaultKeys });
}

function CustomHotkeyBar({ keys }) {
  const { div, span, kbd } = tags;

  return div({ class: css('_flex _aic _gap4 _h[28px] _bgsurface _borderT _bordercolor[#333] _px2') },
    ...keys.map(h =>
      div({ class: css('_flex _aic _gap1 _cursor[pointer]'), onclick: h.action },
        kbd({ class: css('term-hotkey _border _bordercolor[#555] _px1 _textsm') }, h.key),
        span({ class: css('_fgmuted _textsm') }, h.label)
      )
    )
  );
}

function HotkeyBar({ keys, variant = 'standard' }) {
  switch (variant) {
    case 'extended': return ExtendedHotkeyBar({ keys });
    case 'custom': return CustomHotkeyBar({ keys });
    default: return StandardHotkeyBar({ keys });
  }
}
